#include <pybind11/pybind11.h>
#include <pybind11/numpy.h>
#include <pybind11/eigen.h>
#include <Eigen/Dense>

namespace py = pybind11;

py::tuple find_dominant(py::array_t<double> input) {
    py::buffer_info buf1 = input.request();
    int n = buf1.shape[0];

    // Map to Eigen matrix
    Eigen::Map<Eigen::MatrixXd> A((double *)buf1.ptr, n, n);
    // Note: pybind11 default array is row-major (C-contiguous), but Eigen::Map defaults to column-major.
    // If numpy array is C-contiguous, we should specify RowMajor in Map.
    Eigen::Map<Eigen::Matrix<double, Eigen::Dynamic, Eigen::Dynamic, Eigen::RowMajor>> A_rm((double *)buf1.ptr, n, n);

    Eigen::EigenSolver<Eigen::MatrixXd> es(A_rm);
    auto evals = es.eigenvalues();
    auto evecs = es.eigenvectors();

    int max_idx = 0;
    double max_mag = -1.0;
    for (int i = 0; i < n; ++i) {
        double mag = std::norm(evals(i)); // std::norm returns squared magnitude
        if (mag > max_mag) {
            max_mag = mag;
            max_idx = i;
        }
    }

    return py::make_tuple(evals(max_idx), evecs.col(max_idx));
}

PYBIND11_MODULE(ceigen, m) {
    m.def("find_dominant", &find_dominant);
}
EOF
c++ -O3 -Wall -shared -std=c++14 -fPIC $(python3 -m pybind11 --includes) -I/usr/include/eigen3 ceigen.cpp -o ceigen$(python3-config --extension-suffix)
